const data = $input.first().json;
const stepFiles = data?.steps?.step_11_normalizer_output?.root_files ?? [];
const normFiles = data?.normalization?.final_stats ?? [];
const updated = Array.isArray(stepFiles) ? stepFiles.find(f => f?.filename === 'updated_spec_value_counts_cumulative.csv') : null;
const final_ = Array.isArray(normFiles) ? normFiles.find(f => f?.filename === 'final_spec_value_counts_cumulative.csv') : null;
const picked = updated || final_;
if (picked?.url) return [{ json: { target_url: picked.url, filename: picked.filename, source: updated ? 'step_11' : 'normalization' } }];
return [{ json: { target_url: null } }];

const allItems = $input.all();
if (!allItems || allItems.length === 0) return [{ json: { buyer_specs: [] } }];
const grouped = {};
for (const item of allItems) {
  const row = item.json;
  const spec = row.normalised_spec_name;
  if (!spec) continue;
  if (!grouped[spec]) grouped[spec] = { spec_name: spec, total_product_count: 0, option_map: {} };
  const count = Number(row.prod_count || 0);
  grouped[spec].total_product_count += count;
  let value = row.normalised_spec_value || '';
  if (row.normalised_spec_value_unit) value = `${value} ${row.normalised_spec_value_unit}`;
  value = value.trim();
  if (!value) continue;
  grouped[spec].option_map[value] = (grouped[spec].option_map[value] || 0) + count;
}
const buyer_specs = Object.values(grouped)
  .filter(s => s.total_product_count > 0)
  .sort((a, b) => b.total_product_count - a.total_product_count)
  .slice(0, 20)
  .map(spec => {
    const sortedOptions = Object.entries(spec.option_map).sort((a, b) => b[1] - a[1]).slice(0, 6).map(([v]) => v);
    return { spec_name: spec.spec_name, total_product_count: spec.total_product_count, example_values: sortedOptions };
  });
return [{ json: { buyer_specs } }];

// ============================================================
// BUILD MAPPER INPUT
// All 5 sources come through Merge (append mode).
// Identify each source by structure and extract spec name lists.
// ============================================================

const allItems = $input.all().map(i => i.json);

let buyerSpecs = [];
let fillRateRows = [];
let searchRows = [];
let missingSpecsData = null;

// ------------------------------------------------------------
// Identify source type
// ------------------------------------------------------------
for (const item of allItems) {

  // Buyer specs
  if (Array.isArray(item.buyer_specs)) {
    buyerSpecs = item.buyer_specs;
    continue;
  }

  // Missing specs (seller specs)
  if (item.finalized_specs && typeof item.finalized_specs === 'object' && !Array.isArray(item.finalized_specs)) {
    missingSpecsData = item;
    continue;
  }

  // Fill rate rows
  if (item['spec_fill_rate'] !== undefined || item['Spec Fill Rate'] !== undefined) {
    fillRateRows.push(item);
    continue;
  }

  // Search rows
  if (
    item['Impression'] !== undefined ||
    item['impression'] !== undefined ||
    item['Spec Option'] !== undefined ||
    item['Total Impressions'] !== undefined
  ) {
    searchRows.push(item);
    continue;
  }

  // Fallback detection
  if (item.mcat_id !== undefined && item.spec_name !== undefined) {
    if (item.product_count !== undefined) fillRateRows.push(item);
    else searchRows.push(item);
  }
}

// ------------------------------------------------------------
// Extract seller spec names
// ------------------------------------------------------------
let missingSpecs = missingSpecsData?.finalized_specs || {};

const sellerSpecNames = [];

for (const tier of [
  'finalized_primary_specs',
  'finalized_secondary_specs',
  'finalized_tertiary_specs'
]) {
  const tierSpecs = missingSpecs?.[tier]?.specs || [];
  for (const s of tierSpecs) {
    if (s?.spec_name) sellerSpecNames.push(String(s.spec_name).trim());
  }
}

// ------------------------------------------------------------
// Category info
// ------------------------------------------------------------
const categoryName =
  missingSpecsData?.mcat_name ||
  missingSpecsData?.category_name ||
  'Unknown';

const mcatId = missingSpecsData?.mcat_id || null;


// ------------------------------------------------------------
// Buyer call spec names
// ------------------------------------------------------------
const buyerCallSpecNames = buyerSpecs
  .map(s => String(s?.spec_name ?? '').trim())
  .filter(n => n !== '');


// ------------------------------------------------------------
// Fill rate spec names
// ------------------------------------------------------------
const fillRateSpecNames = fillRateRows
  .map(r => String(r['Spec Name'] ?? r['spec_name'] ?? '').trim())
  .filter(n => n !== '' && isNaN(Number(n)));


// ------------------------------------------------------------
// Search spec names (deduplicated)
// ------------------------------------------------------------
const searchSpecNames = [
  ...new Set(
    searchRows
      .map(r => String(r['Spec Name'] ?? r['spec_name'] ?? '').trim())
      .filter(n => n !== '' && isNaN(Number(n)))
  )
];


// ------------------------------------------------------------
// Output
// ------------------------------------------------------------
return [
  {
    json: {
      category_name: categoryName,
      mcat_id: mcatId,

      seller_spec_names: sellerSpecNames,
      buyer_call_spec_names: buyerCallSpecNames,
      fill_rate_spec_names: fillRateSpecNames,
      search_spec_names: searchSpecNames,

      // raw data for join node
      _raw_seller_specs: missingSpecs,
      _raw_buyer_specs: buyerSpecs,
      _raw_fill_rate_rows: fillRateRows,
      _raw_search_rows: searchRows
    }
  }
];

// Parse mapper output — extract name mappings only

const first = $input.first().json;
const llmOutput = first.output ?? first.text;

if (!llmOutput || typeof llmOutput !== 'string') {
  throw new Error('No string output from Mapper Agent.');
}

// Remove markdown if model accidentally adds it
let clean = llmOutput
  .replace(/```json\s*/gi, '')
  .replace(/```\s*/g, '')
  .trim();

let parsed;

try {
  parsed = JSON.parse(clean);
} catch (e) {

  // attempt simple repair
  let repaired = clean
    .replace(/,\s*([}\]])/g, '$1')
    .replace(/}\s*{/g, '},{')
    .replace(/,\s*,/g, ',')
    .replace(/[\u0000-\u001F]+/g, '');

  try {
    parsed = JSON.parse(repaired);
  } catch (err) {
    throw new Error('Invalid JSON from Mapper.\n' + clean.slice(0, 500));
  }
}

// Normalize mappings
const mappings = (parsed.mappings || []).map(m => ({
  seller_spec_name: m.seller_spec_name,
  matched_call_names: m.matched_call_names || [],
  matched_fill_rate_names: m.matched_fill_rate_names || [],
  matched_search_names: m.matched_search_names || [],
  match_confidence: m.match_confidence || 'low'
}));

return [{
  json: {
    category_name: parsed.category_name ?? null,
    mappings
  }
}];

// ============================================================
// JOIN NUMBERS — Use mapper name mapping to pull actual numbers
// from raw source data. LLM never touches numbers.
// ============================================================

// ---------- Helper: normalize spec names ----------
function norm(s) {
  return (s || '')
    .toString()
    .toLowerCase()
    .replace(/\s+/g, ' ')
    .replace(/\(.*?\)/g, '') // remove units like (mm)
    .trim();
}

const mapperOutput = $('Parse Mapper Output').first().json || {};
const inputData = $('Build Mapper Input').first().json || {};

const {
  _raw_seller_specs = {},
  _raw_buyer_specs = [],
  _raw_fill_rate_rows = [],
  _raw_search_rows = []
} = inputData;

const mcatId = inputData.mcat_id;
const categoryName = inputData.category_name;


// ============================================================
// 1. Buyer Call lookup (ONLY product count now)
// ============================================================

const callLookup = {};

for (const bs of _raw_buyer_specs) {
  const key = norm(bs.spec_name);

  callLookup[key] = {
    total_product_count: Number(bs.total_product_count || 0)
  };
}


// ============================================================
// 2. Fill rate lookup
// ============================================================

const fillLookup = {};

for (const row of _raw_fill_rate_rows) {
  const name = norm(row['Spec Name'] || row['spec_name']);
  if (!name) continue;

  fillLookup[name] = {
    fill_rate: Number(row['Spec Fill Rate'] || row['spec_fill_rate'] || 0),
    product_count: Number(row['product_count'] || 0)
  };
}


// ============================================================
// 3. Search data lookup
// ============================================================

const searchLookup = {};

for (const row of _raw_search_rows) {
  const name = norm(row['Spec Name'] || row['spec_name']);
  if (!name) continue;

  const imp = Number(row['Impression'] || row['impression'] || 0);
  searchLookup[name] = (searchLookup[name] || 0) + imp;
}


// ============================================================
// 4. Seller spec metadata (WITH OPTIONS)
// ============================================================

const sellerMeta = {};

let sellerSpecs = _raw_seller_specs;

// unwrap safety
if (Array.isArray(sellerSpecs)) {
  const first = sellerSpecs[0] || {};
  sellerSpecs = first.finalized_specs || first;
}
if (sellerSpecs.finalized_specs && typeof sellerSpecs.finalized_specs === 'object') {
  sellerSpecs = sellerSpecs.finalized_specs;
}

const tierMap = {
  finalized_primary_specs: 'Primary',
  finalized_secondary_specs: 'Secondary',
  finalized_tertiary_specs: 'Tertiary'
};

for (const [tierKey, tierLabel] of Object.entries(tierMap)) {

  const block = sellerSpecs[tierKey];
  if (!block || !block.specs) continue;

  for (const spec of block.specs) {

    const key = norm(spec.spec_name);

    sellerMeta[key] = {
      current_tier: tierLabel,
      option_count: spec.options ? spec.options.length : 0,
      input_type: spec.input_type || 'radio_button',
      options: Array.isArray(spec.options) ? spec.options : []
    };
  }
}


// ============================================================
// 5. Join using mapper mappings
// ============================================================

const unified = [];

for (const m of (mapperOutput.mappings || [])) {

  const name = m.seller_spec_name;
  const key = norm(name);

  const meta = sellerMeta[key] || {
    current_tier: 'Unknown',
    option_count: 0,
    input_type: 'radio_button',
    options: []
  };


  // -----------------------------
  // Buyer Call product count
  // -----------------------------
  let prodCount = 0;

  for (const cn of (m.matched_call_names || [])) {
    const f = callLookup[norm(cn)];
    if (f) {
      prodCount += f.total_product_count;
    }
  }


  // -----------------------------
  // Fill rate
  // -----------------------------
  let fillRate = 0;

  for (const fn of (m.matched_fill_rate_names || [])) {
    const f = fillLookup[norm(fn)];
    if (f) fillRate = Math.max(fillRate, f.fill_rate);
  }


  // -----------------------------
  // Search impressions
  // -----------------------------
  let impressions = 0;

  for (const sn of (m.matched_search_names || [])) {
    const f = searchLookup[norm(sn)];
    if (f) impressions += f;
  }


  // ============================================================
  // 6. Unified spec record (FINAL)
  // ============================================================

  unified.push({

    spec_name: name,
    current_tier: meta.current_tier,

    option_count: meta.option_count,
    input_type: meta.input_type,

    product_count: prodCount,
    fill_rate: fillRate,
    impression: impressions,

    // ✅ ONLY seller-side values now
    seller_options: meta.options,

    match_confidence: m.match_confidence || 'unknown'
  });

}


// ============================================================
// OUTPUT
// ============================================================

return [{
  json: {
    category_name: categoryName,
    mcat_id: mcatId,
    unified_specs: unified
  }
}];

// ------------------------------------------------
// Parse Branch A LLM output (robust version)
// ------------------------------------------------

const first = $input.first().json;

let raw =
  first.output ??
  first.text ??
  first.message ??
  first.response ??
  null;

if (raw && typeof raw === 'object' && raw.output) raw = raw.output;


// -----------------------------
// JSON repair function
// -----------------------------
function cleanJson(s) {
  return s
    .replace(/[\u0000-\u001F]+/g, ' ')       // remove control chars
    .replace(/[^\x00-\x7F]+/g, ' ')          // remove non-ASCII garbage (e.g. "перeд")
    .replace(/,\s*}/g, '}')                  // trailing commas
    .replace(/,\s*]/g, ']')
    .replace(/}\s*[A-Za-z]+\s*,/g, '},')     // remove stray tokens between objects
    .replace(/```json/gi, '')                // remove markdown fences
    .replace(/```/g, '')
    .trim();
}

function safeParse(s) {
  try {
    return JSON.parse(cleanJson(s));
  } catch {
    return null;
  }
}

let parsed = null;


// -----------------------------
// Extract JSON
// -----------------------------
if (typeof raw === 'string') {

  const block = raw.match(/```json\s*([\s\S]*?)\s*```/i);

  if (block) parsed = safeParse(block[1]);

  if (!parsed) parsed = safeParse(raw);

}

else if (typeof raw === 'object') {
  parsed = raw;
}


// -----------------------------
// Fail safe
// -----------------------------
if (!parsed) {
  return [{
    json: {
      branch: 'A',
      error: 'Parse failed',
      raw_sample: String(raw).slice(0,500)
    }
  }];
}


// -----------------------------
// Extract results container
// -----------------------------
function findResults(o) {

  if (!o) return null;

  if (Array.isArray(o.results)) return o;

  for (const k of ['output','data','response']) {
    if (o[k] && Array.isArray(o[k].results)) return o[k];
  }

  return null;
}

const container = findResults(parsed);

if (!container) {
  return [{
    json: {
      branch: 'A',
      error: 'No results[]'
    }
  }];
}


// -----------------------------
// Success
// -----------------------------
return [{
  json: {
    branch: 'A',
    ...container
  }
}];

return $input.all().map(item => {
    let fs = item.json.final_specs;
    let parsed = {};

    // 🧹 Step 1: Clean known bad patterns (defensive fix)
    if (typeof fs === 'string') {
        try {
            // Remove duplicate/broken trailing input_type entries
            fs = fs.replace(/,\s*"input_type"\s*:\s*"radio_button"\s*}/g, '}');

            // Remove any dangling input_type outside objects
            fs = fs.replace(/,\s*"input_type"\s*:\s*"radio_button"\s*(?=[,\]])/g, '');

        } catch (e) {
            console.log("Pre-clean error:", e.message);
        }
    }

    // 🧠 Step 2: Safe JSON parsing
    if (fs) {
        try {
            parsed = typeof fs === 'string' ? JSON.parse(fs) : fs;
        } catch (e) {
            console.log("❌ JSON PARSE ERROR:", e.message);
            console.log("RAW INPUT:", fs);
            parsed = {};
        }
    }

    // 🔍 Step 3: Extract finalized specs safely
    let finalSpecs = {};

    if (Array.isArray(parsed)) {
        const first = parsed[0] || {};

        if (first.finalized_specs && typeof first.finalized_specs === 'object') {
            finalSpecs = first.finalized_specs;

        } else if (first.finalized_primary_specs) {
            finalSpecs = first;
        }

    } else if (parsed.finalized_specs && typeof parsed.finalized_specs === 'object') {
        finalSpecs = parsed.finalized_specs;

    } else if (parsed.finalized_primary_specs) {
        finalSpecs = parsed;
    }

    // 🛡️ Step 4: अंतिम fallback (avoid blank output)
    if (!finalSpecs || Object.keys(finalSpecs).length === 0) {
        console.log("⚠️ Empty finalSpecs for mcat:", item.json.mcat_id);
    }

    return {
        json: {
            mcat_id: item.json.mcat_id,
            mcat_name: item.json.mcat_name,
            finalized_specs: finalSpecs
        }
    };
});

const output = [];

for (const item of $input.all()) {
  const branch = item.json.branch;
  const mcat_id = item.json.mcat_id;
  const category_name = item.json.category_name;
  const method = item.json.method;

  const results = item.json.results || [];

  for (const spec of results) {
    output.push({
      json: {
        branch,
        mcat_id,
        category_name,
        method,
        spec_name: spec.spec_name,
        current_tier: spec.current_tier,
        final_rank: spec.final_rank,
        final_tier: spec.final_tier,
        sanity_tags: (spec.sanity_tags || []).join(", "),
        change_reason: spec.change_reason
      }
    });
  }
}

return output;

// =======================================================
// REBUILD FINAL SPEC STRUCTURE USING NEW SEQUENCE
// =======================================================

// Sequencing output rows
const rows = $input.all().map(i => i.json);

// Get original spec structure
const original = $('Get Missing Specs').first().json;

// Extract category info
const categoryName = original.mcat_name || original.category_name || null;
const mcatId = original.mcat_id || null;

// Flatten original specs into lookup
const specLookup = {};

const tiers = [
  'finalized_primary_specs',
  'finalized_secondary_specs',
  'finalized_tertiary_specs'
];

for (const t of tiers) {
  const specs = original.finalized_specs?.[t]?.specs || [];

  for (const s of specs) {
    specLookup[s.spec_name] = {
      spec_name: s.spec_name,
      options: s.options || [],
      input_type: s.input_type || 'radio_button'
    };
  }
}

// Sort sequencing rows by rank
rows.sort((a,b) => Number(a.final_rank) - Number(b.final_rank));

const primary = [];
const secondary = [];
const tertiary = [];

// Build new spec structure
for (const r of rows) {

  const spec = specLookup[r.spec_name];
  if (!spec) continue;

  if (r.final_tier === 'Primary') {
    primary.push(spec);
  }
  else if (r.final_tier === 'Secondary') {
    secondary.push(spec);
  }
  else {
    tertiary.push(spec);
  }
}

// Final output structure
return [{
  json: {
    category_name: categoryName,
    mcat_id: mcatId,
    finalized_specs: {
      finalized_primary_specs: { specs: primary },
      finalized_secondary_specs: { specs: secondary },
      finalized_tertiary_specs: { specs: tertiary }
    }
  }
}];

// ============================================================
// FLATTEN unified_specs → one item per spec
// ============================================================

const item = $input.first().json;

const categoryName = item.category_name;
const mcatId = item.mcat_id;
const specs = item.unified_specs || [];

const out = [];

for (const s of specs) {

  out.push({
    json: {
      category_name: categoryName,
      mcat_id: mcatId,

      spec_name: s.spec_name,
      current_tier: s.current_tier,

      option_count: s.option_count,
      input_type: s.input_type,

      product_count: s.product_count,
      fill_rate: s.fill_rate,
      impression: s.impression,

      example_values: s.example_values,
      match_confidence: s.match_confidence
    }
  });

}

return out;

const input = $input.first().json;

const category = input.category_name;
const mappings = input.mappings || [];

const rows = [];

for (const m of mappings) {

  const sellerSpec = m.seller_spec_name;
  const confidence = m.match_confidence;

  for (const v of m.matched_call_names || []) {
    rows.push({
      category_name: category,
      seller_spec_name: sellerSpec,
      source_type: "call",
      source_spec_name: v,
      match_confidence: confidence
    });
  }

  for (const v of m.matched_fill_rate_names || []) {
    rows.push({
      category_name: category,
      seller_spec_name: sellerSpec,
      source_type: "fill_rate",
      source_spec_name: v,
      match_confidence: confidence
    });
  }

  for (const v of m.matched_search_names || []) {
    rows.push({
      category_name: category,
      seller_spec_name: sellerSpec,
      source_type: "search",
      source_spec_name: v,
      match_confidence: confidence
    });
  }

}

return rows.map(r => ({ json: r }));
